import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface NutritionData {
  caloriesConsumed: number;
  macrosBreakdown: {
    carbohydrates: number;
    proteins: number;
    fats: number;
  };
  mealCount: number;
}

export default function Widget() {
  const nutritionData = response.data as NutritionData;
  const { caloriesConsumed, macrosBreakdown, mealCount } = nutritionData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 400,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#1E1E1E',
        color: theme === 'light' ? '#000000' : '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              Nutrition Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Daily Calories Consumed
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              {caloriesConsumed} kcal
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Macros Breakdown
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {Object.entries(macrosBreakdown).map(([macro, value]) => (
                <Chip
                  key={macro}
                  label={`${macro.charAt(0).toUpperCase() + macro.slice(1)}: ${value}g`}
                  sx={{
                    fontSize: '11px',
                    px: 1,
                    py: 0.5,
                    bgcolor: accentColor,
                    color: '#FFFFFF',
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Meals Today
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              {mealCount}
            </Typography>
          </Box>

          <PieChart
            height={140}
            series={[
              {
                data: [
                  { value: macrosBreakdown.carbohydrates, label: 'Carbs' },
                  { value: macrosBreakdown.proteins, label: 'Proteins' },
                  { value: macrosBreakdown.fats, label: 'Fats' },
                ],
                color: [primaryColor, accentColor, '#FF9800'],
                label: {
                  type: 'inner',
                  fontSize: 10,
                  color: theme === 'light' ? '#000000' : '#FFFFFF',
                },
              },
            ]}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 0,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
